class GridActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_grid)

        val display = windowManager.defaultDisplay
        val displayMetrics = DisplayMetrics()
        display.getMetrics(displayMetrics)
        val screenWidthDp = displayMetrics.widthPixels / displayMetrics.density

        val columnCount = (screenWidthDp / 180).toInt().coerceAtLeast(1)
        val recyclerView = findViewById<RecyclerView>(R.id.grid)
        recyclerView.layoutManager = GridLayoutManager(this, columnCount)
    }
}

questions.solution:
class GridActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_grid)

        val metrics = WindowMetricsCalculator.getOrCreate()
            .computeCurrentWindowMetrics(this)
        val widthDp = metrics.bounds.width() /
            resources.displayMetrics.density

        val columnCount = (widthDp / 180).toInt().coerceAtLeast(1)
        val recyclerView = findViewById<RecyclerView>(R.id.grid)
        recyclerView.layoutManager = GridLayoutManager(this, columnCount)
    }
}
